// TIER 4 merge + finalize: fill email/phone/socials from the contact scraper, then output clean rows.
const norm = (s) => (s == null ? '' : String(s)).toLowerCase().replace(/\s+/g, ' ').trim();
const joinArr = (a) => Array.isArray(a) ? a.filter(Boolean).join(', ') : (a || '');
const firstOf = (a) => (Array.isArray(a) && a[0]) ? a[0] : '';
const hostOf = (u) => { try { return new URL(u).hostname.replace(/^www\./, ''); } catch (e) { return ''; } };
let contacts = [];
try { contacts = $('Retrieve Contact Data').all().map((i) => i.json); } catch (e) { contacts = []; }
const byHost = {};
for (const it of contacts) { const hh = it.domain || hostOf(it.originalStartUrl); if (hh) byHost[hh] = it; }
return $('Assign Candidate Websites').all().map(({ json: l }) => {
  if (!l.email && l.website) {
    const it = byHost[hostOf(l.website)] || {};
    const em = firstOf(it.emails);
    if (em) { l.email = em; l.contactSource = 'website-contact'; }
    if (!l.phone) l.phone = firstOf(it.phones) || '';
    if (!l.socials) l.socials = [it.instagrams, it.facebooks, it.youtubes].map(joinArr).filter(Boolean).join(' | ');
  }
  const { _key, _dest, ...row } = l;
  return { json: row };
});

// TIER 1: map Booking items -> lead rows; contact comes from traderInfo (region-gated).
const dest = $('Set Destination and Parameters').first().json.destination;
const norm = (s) => (s == null ? '' : String(s)).toLowerCase().replace(/\s+/g, ' ').trim();
return $('Retrieve Booking Data').all().map(({ json: b }) => {
  const t = b.traderInfo || {}, h = b.hostInfo || {}, ta = t.address || {};
  const traderAddress = [ta.street, [ta.postalCode, ta.city].filter(Boolean).join(' '), ta.state, ta.countryCode].filter(Boolean).join(', ');
  return { json: {
    name: b.name || '', type: b.type || '', address: (b.address && b.address.full) || '',
    email: t.email || '', phone: t.phone || '',
    companyName: t.companyName || '', hostName: h.name || '', managedProperties: h.managedProperties != null ? h.managedProperties : '',
    rating: b.rating != null ? b.rating : '', stars: b.stars != null ? b.stars : '', reviews: b.reviews != null ? b.reviews : '',
    city: (b.address && b.address.city) || '', country: ((b.address && b.address.country) || '').toUpperCase(),
    registrationNumber: t.registrationNumber || '', traderAddress,
    website: '', socials: '', contactFormUrl: '',
    contactSource: t.email ? 'booking-trader' : 'none',
    BookingURL: b.url || '', _key: norm(b.name), _dest: dest
  } };
});

// TIER 2 merge: fill email/phone/website/socials from Google Maps for leads still missing email.
const norm = (s) => (s == null ? '' : String(s)).toLowerCase().replace(/\s+/g, ' ').trim();
const joinArr = (a) => Array.isArray(a) ? a.filter(Boolean).join(', ') : (a || '');
const OTA = /booking\.com|agoda|expedia|decolar|hotels\.com|tripadvisor|airbnb|vrbo|trip\.com|hostelworld|trivago|kayak|yelp\.|google\.|facebook\.com|instagram\.com|x\.com|twitter\.com|linkedin\.com|youtube\.com/i;
const cleanSite = (w) => (w && !OTA.test(String(w))) ? String(w) : '';
const firstOf = (a) => (Array.isArray(a) && a[0]) ? a[0] : '';
let maps = [];
try { maps = $('Retrieve Maps Data').all().map((i) => i.json); } catch (e) { maps = []; }
const byKey = {};
for (const c of maps) { if (c && c.searchString) byKey[norm(c.searchString)] = c; if (c && c.title && !byKey[norm(c.title)]) byKey[norm(c.title)] = c; }
return $('Map Booking to Lead Rows').all().map(({ json: l }) => {
  if (!l.email) {
    const c = byKey[norm(l.name + ', ' + l._dest)] || byKey[l._key] || {};
    const em = firstOf(c.emails); const ph = firstOf(c.phones) || c.phone || ''; const site = cleanSite(c.website);
    if (site && !l.website) l.website = site;
    if (!l.socials) l.socials = [c.linkedIns, c.instagrams, c.facebooks, c.twitters, c.youtubes, c.tiktoks].map(joinArr).filter(Boolean).join(' | ');
    if (em) { l.email = em; l.contactSource = 'google-maps'; }
    if (!l.phone && ph) l.phone = ph;
  }
  return { json: l };
});

// TIER 3 merge: assign a candidate website (from Google Search) to leads still missing email AND website.
const norm = (s) => (s == null ? '' : String(s)).toLowerCase().replace(/\s+/g, ' ').trim();
const OTA = /booking\.com|agoda|expedia|decolar|hotels\.com|tripadvisor|airbnb|vrbo|trip\.com|hostelworld|trivago|kayak|yelp\.|google\.|facebook\.com|instagram\.com|x\.com|twitter\.com|linkedin\.com|youtube\.com/i;
const cleanSite = (w) => (w && !OTA.test(String(w))) ? String(w) : '';
let search = [];
try { search = $('Retrieve Search Data').all().map((i) => i.json); } catch (e) { search = []; }
const byTerm = {};
for (const p of search) { const term = p.searchQuery && p.searchQuery.term; if (!term) continue; const url = (p.organicResults || []).map((r) => cleanSite(r.url)).find(Boolean) || ''; if (url) byTerm[norm(term)] = url; }
return $('Merge Maps Data').all().map(({ json: l }) => {
  if (!l.email && !l.website) {
    const q = norm(l.name + ' ' + (l.city || l._dest) + ' official website');
    if (byTerm[q]) l.website = byTerm[q];
  }
  return { json: l };
});
